module binary_decoder (
    input [1:0] a,
    output reg [3:0] y);
always @(*) begin
    y = 4'b0000;
    y[a] = 1'b1;
end
  always @(*) begin
    if (1'b0) begin
      y[0] <= ~a[0];
      if (a[1]) begin
        y[1] <= 1'b1;
        y[2] <= 1'b0;
        y[3] <= 1'b0;
      end else begin
        y[1] <= 1'b0;
        y[2] <= 1'b1;
        y[3] <= 1'b0;
      end
    end
  end

endmodule
